function rgb(r, g, b) {
  return {
    r: Math.min(1, Math.max(0, r / 255)),
    g: Math.min(1, Math.max(0, g / 255)),
    b: Math.min(1, Math.max(0, b / 255)),
  };
}

function hexToRgb(hex) {
  if (hex && typeof hex === "object" && hex.r != null) {
    const scale = hex.r > 1 || hex.g > 1 || hex.b > 1 ? 255 : 1;
    return {
      r: Math.min(1, Math.max(0, hex.r / scale)),
      g: Math.min(1, Math.max(0, hex.g / scale)),
      b: Math.min(1, Math.max(0, hex.b / scale)),
    };
  }
  const str = typeof hex === "string" ? hex : String(hex || "#808080");
  if (str.startsWith("rgba")) {
    const m = str.match(/rgba?\((\d+),\s*(\d+),\s*(\d+)/);
    if (m) return rgb(+m[1], +m[2], +m[3]);
  }
  const h = str.replace("#", "");
  const n = parseInt(h.length >= 6 ? h.slice(0, 6) : h, 16);
  if (!Number.isFinite(n)) return rgb(128, 128, 128);
  return rgb((n >> 16) & 255, (n >> 8) & 255, n & 255);
}

function snap(n) {
  return Math.round(n / GRID) * GRID;
}

function touchSize(n) {
  return Math.max(MIN_TOUCH, snap(n));
}

function setSolidFill(node, hex) {
  node.fills = [{ type: "SOLID", color: hexToRgb(hex) }];
}

function setStroke(node, hex, weight) {
  node.strokes = [{ type: "SOLID", color: hexToRgb(hex) }];
  node.strokeWeight = weight != null ? weight : T.stroke;
}

function resolveFontStyle(requested) {
  if (fontCache[requested]) return fontCache[requested];
  if (fontCache.Regular) return fontCache.Regular;
  return "Regular";
}

function createTextSafe(chars, style, size, color, opacity) {
  if (!fontsReady) throw new Error("loadFonts() first");
  const t = figma.createText();
  t.fontName = { family: FONT_FAMILY, style: resolveFontStyle(style) };
  t.characters = chars;
  t.fontSize = size;
  const fill = { type: "SOLID", color: hexToRgb(color) };
  if (opacity != null) fill.opacity = opacity;
  t.fills = [fill];
  return t;
}

function appendText(parent, chars, style, size, color, x, y, opacity) {
  const t = createTextSafe(chars, style, size, color, opacity);
  t.x = x;
  t.y = y;
  parent.appendChild(t);
  return t;
}

function appendCenteredText(parent, chars, style, size, color, opacity) {
  const t = createTextSafe(chars, style, size, color, opacity);
  t.textAlignHorizontal = "CENTER";
  t.textAlignVertical = "CENTER";
  t.resize(parent.width, parent.height);
  t.x = 0;
  t.y = 0;
  parent.appendChild(t);
  return t;
}

function makeRect(parent, w, h, fill, radius) {
  const r = figma.createRectangle();
  r.resize(w, h);
  setSolidFill(r, fill);
  if (radius != null) r.cornerRadius = radius;
  parent.appendChild(r);
  return r;
}

function makeEllipse(parent, w, h, fill) {
  const e = figma.createEllipse();
  e.resize(w, h);
  setSolidFill(e, fill);
  parent.appendChild(e);
  return e;
}

function makeComp(name, w, h) {
  const c = figma.createComponent();
  c.name = name;
  c.resize(snap(w), snap(h));
  c.clipsContent = false;
  return c;
}

function combineVariantSet(setName, parts, propsList) {
  for (let i = 0; i < parts.length; i++) {
    const props = propsList[i];
    const pairs = Object.keys(props).map((k) => `${k}=${props[k]}`);
    parts[i].name = pairs.join(", ");
  }
  const parent = figma.createFrame();
  parent.name = "_variant-temp";
  parent.resize(1, 1);
  parent.visible = false;
  const set = figma.combineAsVariants(parts, parent);
  set.name = setName;
  // Move set off temp frame before remove — Figma destroys all descendants with parent.
  const holder = figma.currentPage;
  if (holder) holder.appendChild(set);
  parent.remove();
  INVENTORY.variantSets.push({ name: setName, variants: parts.length });
  INVENTORY.totalVariants += parts.length;
  return set;
}

function registerSingle(name, comp) {
  comp.name = name;
  INVENTORY.components.push(name);
  return comp;
}

async function loadFonts() {
  fontsReady = false;
  const warnings = [];
  for (const style of FONT_STYLES) {
    try {
      await figma.loadFontAsync({ family: FONT_FAMILY, style });
      fontCache[style] = style;
    } catch (e) {
      warnings.push(`${FONT_FAMILY} ${style}: ${e.message || e}`);
    }
  }
  if (!fontCache.Regular) {
    await figma.loadFontAsync({ family: FONT_FAMILY, style: "Regular" });
    fontCache.Regular = "Regular";
  }
  fontsReady = true;
  return warnings;
}

function getAllPages() {
  return figma.root.children.filter((p) => p.type === "PAGE");
}

function resolveUserFlowPage() {
  const pages = getAllPages();
  const exact = pages.find((p) => p.name === PAGE_NAME);
  if (exact) return { page: exact, log: [`[page] ${PAGE_NAME}`] };
  const legacy = pages.find((p) => LEGACY_USER_FLOW_ALIASES.has(p.name));
  if (legacy) {
    try {
      legacy.name = PAGE_NAME;
    } catch (_) {}
    return { page: legacy, log: [`[page rename] → ${PAGE_NAME}`] };
  }
  if (pages.length) return { page: pages[0], log: [`[page fallback] ${pages[0].name}`] };
  throw new Error("No pages found");
}

function removeExistingLibrary(page) {
  for (const child of [...page.children]) {
    if (child.type === "FRAME" && child.name === LIBRARY_FRAME_NAME) {
      try {
        child.remove();
      } catch (_) {}
    }
  }
}

