function drawIconBack(parent, color, size) {
  const s = size || 24;
  const bar = makeRect(parent, s * 0.55, 2, color, 1);
  bar.x = s * 0.2;
  bar.y = s * 0.5 - 1;
  const tri = figma.createPolygon();
  tri.pointCount = 3;
  tri.resize(s * 0.35, s * 0.35);
  setSolidFill(tri, color);
  tri.rotation = -90;
  tri.x = s * 0.08;
  tri.y = s * 0.32;
  parent.appendChild(tri);
}

function drawIconPlus(parent, color, size) {
  const s = size || 24;
  makeRect(parent, s * 0.55, 2, color, 1).x = s * 0.22;
  makeRect(parent, s * 0.55, 2, color, 1).x = s * 0.22;
  parent.children[parent.children.length - 1].y = s * 0.49;
  parent.children[parent.children.length - 2].y = s * 0.22;
  const v = makeRect(parent, 2, s * 0.55, color, 1);
  v.x = s * 0.49;
  v.y = s * 0.22;
}

