function bytesFromBase64(b64) {
  const binary = atob(b64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
  return bytes;
}

async function loadKioskIconSheet() {
  kioskIconImage = null;
  kioskIconImagesBySpec = {};
  const specEntries = Object.entries(KIOSK_ICON_B64_BY_SPEC || {});
  if (specEntries.length) {
    for (const [name, b64] of specEntries) {
      if (!b64) continue;
      try {
        kioskIconImagesBySpec[name] = figma.createImage(bytesFromBase64(b64));
      } catch (e) {
        console.warn("[DS-02] kiosk icon load failed:", name, e.message || e);
      }
    }
    console.log(
      "[DS-02] kiosk individual icons loaded:",
      Object.keys(kioskIconImagesBySpec).length
    );
    return kioskIconImagesBySpec;
  }
  if (!KIOSK_ICONS_B64) {
    console.warn("[DS-02] KIOSK_ICONS_B64 empty — run embed_kiosk_icons.py");
    return null;
  }
  try {
    kioskIconImage = figma.createImage(bytesFromBase64(KIOSK_ICONS_B64));
    console.log("[DS-02] kiosk icon sheet loaded");
  } catch (e) {
    console.warn("[DS-02] kiosk icon sheet load failed:", e.message || e);
  }
  return kioskIconImage;
}

function kioskIconTransform(col, row) {
  const s = 0.25;
  // Maps fill unit square → image UV [col*s, row*s] … [(col+1)*s, (row+1)*s].
  // imageTransform applies only when scaleMode is "CROP" (not FILL/FIT).
  return [
    [s, 0, col * s],
    [0, s, row * s],
  ];
}

function buildIconSheetComponents() {
  if (!kioskIconImage && !Object.keys(kioskIconImagesBySpec).length) return [];
  const out = [];
  const sz = KIOSK_ICON_SIZE;
  for (const spec of KIOSK_ICON_SPECS) {
    const comp = figma.createComponent();
    comp.name = `DS-02 / Icon / ${spec.name}`;
    comp.resize(sz, sz);
    comp.fills = [];
    comp.clipsContent = false;
    const rect = figma.createRectangle();
    rect.resize(sz, sz);
    rect.x = 0;
    rect.y = 0;
    const raster = kioskIconImagesBySpec[spec.name];
    if (raster) {
      rect.fills = [
        {
          type: "IMAGE",
          imageHash: raster.hash,
          scaleMode: "FILL",
        },
      ];
    } else if (kioskIconImage) {
      rect.fills = [
        {
          type: "IMAGE",
          imageHash: kioskIconImage.hash,
          scaleMode: "CROP",
          imageTransform: kioskIconTransform(spec.col, spec.row),
        },
      ];
    } else {
      continue;
    }
    comp.appendChild(rect);
    registerSingle(`DS-02 / Icon / ${spec.name}`, comp);
    out.push(comp);
  }
  return out;
}

