function buildMagnificStyleSvg(inner, color) {
  const stroke = color || T.primary;
  return (
    '<svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24"' +
    ' fill="none" stroke="' +
    stroke +
    '" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">' +
    inner +
    "</svg>"
  );
}

function recolorSvgSubtree(node, colorHex) {
  const paint = [{ type: "SOLID", color: hexToRgb(colorHex) }];
  if ("strokes" in node && node.strokes && node.strokes.length) node.strokes = paint;
  if ("fills" in node && node.fills && Array.isArray(node.fills) && node.fills.length) {
    const f0 = node.fills[0];
    if (f0 && f0.type === "SOLID") node.fills = paint;
  }
  if ("children" in node) {
    for (const child of node.children) recolorSvgSubtree(child, colorHex);
  }
}

function fitSvgNodeToSlot(node, slotW, slotH) {
  const w = node.width;
  const h = node.height;
  if (!w || !h) return;
  const scale = Math.min(slotW / w, slotH / h);
  if (scale > 0 && scale !== 1 && typeof node.rescale === "function") node.rescale(scale);
}

function buildMagnificStyleIconComponent(spec) {
  const color = spec.primary ? T.accent : T.primary;
  const svgRoot = figma.createNodeFromSvg(buildMagnificStyleSvg(spec.inner, color));
  recolorSvgSubtree(svgRoot, color);
  fitSvgNodeToSlot(svgRoot, MAGNIFIC_UI_ICON_SLOT, MAGNIFIC_UI_ICON_SLOT);

  const compName = `DS-02 / Icon / UI / ${spec.name}`;
  const comp = makeComp(compName, MAGNIFIC_UI_COMPONENT_SIZE, MAGNIFIC_UI_COMPONENT_SIZE);
  setSolidFill(comp, T.surface);
  comp.cornerRadius = T.radiusMd;
  setStroke(comp, T.border);

  svgRoot.x = (MAGNIFIC_UI_COMPONENT_SIZE - svgRoot.width) / 2;
  svgRoot.y = (MAGNIFIC_UI_COMPONENT_SIZE - svgRoot.height) / 2;
  comp.appendChild(svgRoot);

  return registerSingle(compName, comp);
}

function buildMagnificStyleIcons() {
  return MAGNIFIC_UI_ICON_SPECS.map((spec) => buildMagnificStyleIconComponent(spec));
}

function buildIconComponent(label) {
  const comp = makeComp(`DS-02 / Icon / ${label}`, 48, 48);
  setSolidFill(comp, T.surface);
  comp.cornerRadius = T.radiusMd;
  setStroke(comp, T.border);
  const iconFrame = figma.createFrame();
  iconFrame.resize(24, 24);
  iconFrame.fills = [];
  iconFrame.x = 12;
  iconFrame.y = 12;
  comp.appendChild(iconFrame);
  const drawer = ICON_DRAWERS[label];
  if (drawer) drawer(iconFrame, T.primary, 24);
  return registerSingle(`DS-02 / Icon / ${label}`, comp);
}

