function createButtonPart(styleDef, sizeDef) {
  const h = touchSize(sizeDef.height);
  const c = makeComp("btn", sizeDef.minWidth, h);
  c.cornerRadius = T.radiusBtn;
  if (styleDef.fill === "transparent") c.fills = [];
  else setSolidFill(c, styleDef.fill);
  if (styleDef.stroke) setStroke(c, styleDef.stroke);
  c.opacity = styleDef.opacity;
  appendCenteredText(c, styleDef.label, "Bold", sizeDef.fontSize, styleDef.text, styleDef.opacity < 1 ? styleDef.opacity : null);
  return c;
}

function buildButtonSet() {
  const specs = [];
  const parts = [];
  for (const styleDef of BUTTON_STYLE_DEFS) {
    for (const sizeDef of BUTTON_SIZE_DEFS) {
      specs.push({ Style: styleDef.Style, Size: sizeDef.Size });
      parts.push(createButtonPart(styleDef, sizeDef));
    }
  }
  return combineVariantSet("DS-02 / Button", parts, specs);
}

function findButtonVariant(buttonSet, style, size) {
  if (!buttonSet || !buttonSet.children) return null;
  for (const child of buttonSet.children) {
    if (child.name.includes("Style=" + style) && child.name.includes("Size=" + size)) return child;
  }
  return buttonSet.children[0] || null;
}

function buildButtonDocShowcase(buttonSet) {
  const outer = figma.createFrame();
  outer.name = "DS-02 · Doc / Buttons";
  outer.resize(920, 720);
  outer.fills = [];
  outer.clipsContent = false;

  const header = figma.createFrame();
  header.name = "header_light";
  header.resize(920, 96);
  setSolidFill(header, T.surface);
  header.x = 0;
  header.y = 0;
  outer.appendChild(header);
  appendText(header, "Buttons", "Bold", 28, T.text, 32, 32);

  const footer = figma.createFrame();
  footer.name = "footer";
  footer.resize(920, 130);
  setSolidFill(footer, T.bg);
  footer.x = 0;
  footer.y = 590;
  outer.appendChild(footer);

  const panel = figma.createFrame();
  panel.name = "doc_button";
  panel.resize(856, 462);
  panel.x = 32;
  panel.y = 112;
  setSolidFill(panel, T.surface);
  panel.cornerRadius = T.radiusDoc;
  panel.effects = [
    {
      type: "DROP_SHADOW",
      color: { r: 0, g: 0, b: 0, a: 0.1 },
      offset: { x: 0, y: 4 },
      radius: 16,
      spread: 0,
      visible: true,
      blendMode: "NORMAL",
    },
  ];
  outer.appendChild(panel);

  appendText(panel, "Button variants · DS-02", "Semi Bold", 16, T.textMuted, 24, 20);

  const gridY = 56;
  const colW = 200;
  const rowH = 56;
  let gx = 24;
  let gy = gridY;
  let col = 0;

  for (const styleDef of BUTTON_STYLE_DEFS) {
    const src = findButtonVariant(buttonSet, styleDef.Style, "Medium");
    if (src && typeof src.createInstance === "function") {
      const inst = src.createInstance();
      inst.x = gx;
      inst.y = gy;
      panel.appendChild(inst);
    } else {
      const clone = createButtonPart(styleDef, BUTTON_SIZE_DEFS[1]);
      clone.x = gx;
      clone.y = gy;
      panel.appendChild(clone);
    }
    const tag = createTextSafe(styleDef.Style, "Medium", 11, T.textMuted);
    tag.x = gx;
    tag.y = gy + 44;
    panel.appendChild(tag);
    gx += colW;
    col++;
    if (col >= 4) {
      gx = 24;
      gy += rowH + 36;
      col = 0;
    }
  }

  return outer;
}

