function buildAllComponents() {
  const items = [];
  const builders = [
    ["Typography", buildTypographySet],
    ["Button", buildButtonSet],
    ["IconButton", buildIconButtonSet],
    ["Chip", buildChipSet],
    ["Badge", buildBadgeSet],
    ["TopBar", buildTopBarSet],
    ["BottomBar", buildBottomBarSet],
    ["MenuCard", buildMenuCardSet],
    ["CartLine", buildCartLineSet],
    ["OrderTypeTile", buildOrderTypeTileSet],
    ["OptionRadio", buildOptionRadioSet],
    ["OptionCheckbox", buildOptionCheckboxSet],
    ["Stepper", buildStepperSet],
    ["ModalConfirm", buildModalConfirmSet],
    ["Toast", buildToastSet],
    ["LoadingOverlay", buildLoadingOverlaySet],
    ["PaymentMethod", buildPaymentMethodSet],
    ["SearchBar", buildSearchBarSet],
    ["EmptyState", buildEmptyStateSet],
    ["SectionHeader", buildSectionHeaderSet],
    ["Divider", buildDividerSet],
    ["ProgressStep", buildProgressStepSet],
    ["SegmentedControl", buildSegmentedControlSet],
    ["Skeleton", buildSkeletonSet],
    ["CategoryTab", buildCategoryTabSet],
    ["QuantityBadge", buildQuantityBadgeSet],
  ];
  for (const [name, fn] of builders) {
    try {
      items.push({ category: name, node: fn() });
      console.log(`[DS-02] built variant set: ${name}`);
    } catch (e) {
      throw new Error(`${name}: ${e.message || e}`);
    }
  }
  items.push({ category: "ModalAlert", node: buildModalAlert() });
  items.push({ category: "UpsellCard", node: buildUpsellCard() });
  items.push({ category: "OrderCompleteCard", node: buildOrderCompleteCard() });
  items.push({ category: "PaymentFailCard", node: buildPaymentFailCard() });
  items.push({ category: "BrandHero", node: buildBrandHero() });
  for (const label of Object.keys(ICON_DRAWERS)) {
    if (kioskIconImage && KIOSK_RASTER_ICON_NAMES.has(label)) continue;
    items.push({ category: "Icon", node: buildIconComponent(label) });
  }
  for (const comp of buildIconSheetComponents()) {
    items.push({ category: "IconSheet", node: comp });
  }
  for (const comp of buildMagnificStyleIcons()) {
    items.push({ category: "IconUI", node: comp });
  }
  return items;
}

function isLiveNode(node) {
  if (!node) return false;
  if (node.removed === true) return false;
  return true;
}

function safeNodeSize(node, fallbackW, fallbackH) {
  try {
    if (!isLiveNode(node)) return { w: fallbackW || 200, h: fallbackH || 100 };
    return {
      w: "width" in node ? node.width : fallbackW || 200,
      h: "height" in node ? node.height : fallbackH || 100,
    };
  } catch (_) {
    return { w: fallbackW || 200, h: fallbackH || 100 };
  }
}

function layoutComponentLibrary(page, items) {
  const frame = figma.createFrame();
  frame.name = LIBRARY_FRAME_NAME;
  frame.resize(4800, 3200);
  frame.fills = [{ type: "SOLID", color: hexToRgb(T.bg) }];
  frame.clipsContent = false;
  page.appendChild(frame);

  const pad = GRID * 3;
  let x = pad;
  let y = pad;
  let rowH = 0;
  const colW = 420;
  const gap = GRID * 2;
  let col = 0;
  const maxCols = 10;

  const title = createTextSafe("DS-02 Modern Minimal · Component Library", "Bold", 24, T.text);
  title.x = pad;
  title.y = pad;
  frame.appendChild(title);
  const sub = createTextSafe(
    "Charcoal #1A1C20 + Electric Lime #C8F135 · radius 10/12/16px · 2px stroke · SCR-001~008",
    "Medium",
    12,
    T.textMuted
  );
  sub.x = pad;
  sub.y = pad + 32;
  frame.appendChild(sub);

  y = pad + 64;
  x = pad;
  col = 0;
  rowH = 0;

  let lastCategory = "";
  let placed = 0;
  for (const item of items) {
    const node = item.node;
    if (!isLiveNode(node)) {
      console.warn(`[DS-02 layout] skip removed/missing: ${item.category}`);
      continue;
    }
    try {
      if (item.category !== lastCategory) {
        if (col > 0) {
          y += rowH + gap * 3;
          x = pad;
          col = 0;
          rowH = 0;
        }
        const catLabel = createTextSafe(item.category, "Semi Bold", 14, T.primary);
        catLabel.x = pad;
        catLabel.y = y;
        frame.appendChild(catLabel);
        y += 28;
        x = pad;
        col = 0;
        rowH = 0;
        lastCategory = item.category;
      }
      const { w: nw, h: nh } = safeNodeSize(node);
      node.x = x;
      node.y = y;
      frame.appendChild(node);
      rowH = Math.max(rowH, nh);
      x += Math.max(nw, colW) + gap;
      col++;
      placed++;
      if (col >= maxCols) {
        y += rowH + gap;
        x = pad;
        col = 0;
        rowH = 0;
      }
    } catch (e) {
      console.warn(`[DS-02 layout] skip ${item.category}: ${e.message || e}`);
    }
  }
  if (placed === 0) {
    throw new Error("No live component nodes to place in library frame");
  }

  const buttonItem = items.find((i) => i.category === "Button" && isLiveNode(i.node));
  let docExtraH = 0;
  if (buttonItem) {
    try {
      const doc = buildButtonDocShowcase(buttonItem.node);
      doc.x = pad;
      doc.y = y + rowH + gap * 2;
      frame.appendChild(doc);
      docExtraH = doc.height + gap * 2;
    } catch (e) {
      console.warn(`[DS-02 layout] button doc showcase skipped: ${e.message || e}`);
    }
  }

  const finalH = y + rowH + pad + 64 + docExtraH;
  frame.resize(4800, Math.max(finalH, 800));
  return frame;
}

function getInventorySummary() {
  const singles = INVENTORY.components.length;
  const sets = INVENTORY.variantSets.length;
  const variants = INVENTORY.totalVariants;
  return {
    variantSets: sets,
    singleComponents: singles,
    totalVariants: variants,
    totalComponentNodes: singles + variants,
    sets: INVENTORY.variantSets.map((s) => `${s.name} (${s.variants})`),
    singles: [...INVENTORY.components],
  };
}

